mapper.select:
SELECT s.step_id, s.script_id, s.step_name, s.step_type, s.step_description, s.step_content, s.selector_info, s.input_schema, s.output_schema, s.param_mapping, s.step_order, s.is_required, s.is_active, s.enterprise_id, s.creator_id, s.create_time, s.update_by, s.update_time, sc.script_name FROM datacloud_script_step s LEFT JOIN datacloud_script sc ON s.script_id = sc.script_id WHERE s.enterprise_id = #{query.enterpriseId}
AND s.script_id = #{query.scriptId}
AND s.step_name LIKE CONCAT('%', #{query.stepName}, '%')
AND s.step_type = #{query.stepType}
AND s.is_active = #{query.isActive}
ORDER BY s.step_order ASC, s.create_time DESC

SELECT COUNT(*)
FROM datacloud_script_step
WHERE script_id = #{scriptId}

SELECT MAX(step_order)
FROM datacloud_script_step
WHERE script_id = #{scriptId}

mapper.update:
